from assay_engine._local import require_local_uri, is_loopback_host, NonLocalEndpointError

# 0.0.0.0 rejected?
print("0.0.0.0 loopback?", is_loopback_host("0.0.0.0"))

# DSN where 'host' appears as substring of another key, e.g. 'hostfoo=evil' should NOT trigger,
# but real host must. Also key with leading junk.
for dsn in [
  "hostfoo=evil.com dbname=x",          # not a real host key
  "host=localhost options='-c x=evil'",  # value with = inside quotes
  "host=localhost extra=host=evil.com",  # tricky
  "postgresql://localhost/db?options=-chost%3Devil",  # encoded
]:
    try:
        require_local_uri(dsn, what="x"); print("ACCEPT:", dsn)
    except NonLocalEndpointError: print("REJECT:", dsn)

# bare path that contains '=' but is actually a file path -> treated as DSN. Edge:
for p in ["/tmp/my=file.db", "./data=v1/store"]:
    try: print("ACCEPT path:", p, "->", require_local_uri(p, what="x"))
    except NonLocalEndpointError: print("REJECT path:", p)
EOF

